#include<bits/stdc++.h>
using namespace std;
const int N=1e7+5,M=1e6+5;
int n,tot,p[M],phi[N];
long long sum[N];
bool flag[N];

int main()
{
    scanf("%d",&n);
    phi[1]=1;
    for(int i=2;i<=n;i++)
    {
        if(!flag[i])
        {
            p[++tot]=i;
            phi[i]=i-1;
        }
        for(int j=1;j<=tot&&i*p[j]<=n;j++)
        {
            flag[i*p[j]]=1;
            if(i%p[j]==0)
            {
                phi[i*p[j]]=phi[i]*p[j];
                break;
            }
            phi[i*p[j]]=phi[i]*phi[p[j]];
        }
    }
    for(int i=1;i<=n;i++)
    {
        sum[i]=sum[i-1]+phi[i];
    }
    long long ans=0;
    for(int i=1;i<=tot;i++)
    {
        ans+=sum[n/p[i]]*2-1;
    }
    printf("%lld",ans);
    return 0;
}
